        when (method) {
            HttpMethod.GET -> requestBuilder.get()
            HttpMethod.POST -> requestBuilder.post(requestBody ?: "".toRequestBody(JSON_MEDIA_TYPE))
            HttpMethod.PUT -> requestBuilder.put(requestBody ?: "".toRequestBody(JSON_MEDIA_TYPE))
            HttpMethod.PATCH -> requestBuilder.patch(requestBody ?: "".toRequestBody(JSON_MEDIA_TYPE))
            HttpMethod.DELETE -> {
                if (requestBody != null) requestBuilder.delete(requestBody)
                else requestBuilder.delete()
