    // --- Device Discovery ---

    fun discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        path: String = "/info",
        callback: DeviceDiscoveryCallback
    ) {
        val discoveredDevices = mutableListOf<DeviceInfo>()
        var completedRequests = 0
        val totalRequests = 254

        for (i in 1..254) {
            val ip = "$subnet.$i"
            val url = "http://$ip:$port$path"

            val quickClient = localClient.newBuilder()
                .connectTimeout(2, TimeUnit.SECONDS)
                .readTimeout(2, TimeUnit.SECONDS)
                .build()

            val request = Request.Builder()
                .url(url)
                .get()
                .build()

            quickClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    synchronized(discoveredDevices) {
                        completedRequests++
                        if (completedRequests >= totalRequests) {
                            callback.onDiscoveryComplete(discoveredDevices.toList())
                        }
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    synchronized(discoveredDevices) {
                        try {
                            val responseBody = response.body?.string()
                            if (response.isSuccessful && responseBody != null) {
