    // --- Private Helpers ---

    private fun executeRequest(request: Request, client: OkHttpClient, callback: ApiCallback) {
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url} - ${e.message}")
                callback.onError(ApiError(
                    message = e.message ?: "Unknown error",
                    exception = e,
                    url = request.url.toString()
                ))
            }

            override fun onResponse(call: Call, response: Response) {
                try {
                    val responseBody = response.body?.string()
                    val apiResponse = ApiResponse(
                        statusCode = response.code,
                        body = responseBody,
                        headers = response.headers.toMap(),
                        isSuccessful = response.isSuccessful,
                        url = request.url.toString()
                    )

                    if (response.isSuccessful) {
                        callback.onSuccess(apiResponse)
                    } else {
                        callback.onError(ApiError(
                            message = "HTTP ${response.code}: ${response.message}",
                            statusCode = response.code,
                            responseBody = responseBody,
                            url = request.url.toString()
                        ))
                    }
                } catch (e: Exception) {
                    callback.onError(ApiError(
                        message = e.message ?: "Error reading response",
                        exception = e,
                        url = request.url.toString()
                    ))
                } finally {
                    response.close()
                }
            }
        })
    }

    private fun executeRequestSync(request: Request, client: OkHttpClient): ApiResponse {
        val response = client.newCall(request).execute()
        return try {
            val responseBody = response.body?.string()
            ApiResponse(
                statusCode = response.code,
                body = responseBody,
                headers = response.headers.toMap(),
                isSuccessful = response.isSuccessful,
                url = request.url.toString()
            )
        } finally {
            response.close()
        }
    }

    private fun Headers.toMap(): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until size) {
            map[name(i)] = value(i)
        }
        return map
    }

    fun shutdown() {
        secureClient.dispatcher.executorService.shutdown()
        secureClient.connectionPool.evictAll()
        localClient.dispatcher.executorService.shutdown()
        localClient.connectionPool.evictAll()
    }

    // --- Interceptors ---

    private inner class LoggingInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val request = chain.request()
            val startTime = System.nanoTime()

            Log.d(TAG, "--> ${request.method} ${request.url}")
            request.headers.forEach { (name, value) ->
                Log.d(TAG, "    $name: $value")
            }

            val response: Response
            try {
                response = chain.proceed(request)
            } catch (e: Exception) {
                Log.e(TAG, "<-- FAILED: ${request.url} - ${e.message}")
                throw e
            }

            val durationMs = (System.nanoTime() - startTime) / 1_000_000
            Log.d(TAG, "<-- ${response.code} ${request.url} (${durationMs}ms)")

            return response
        }
    }

    private inner class AuthInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val originalRequest = chain.request()

            // Only add auth token for cloud API requests
            if (originalRequest.url.host == "api.example.com" && authToken != null) {
                val authenticatedRequest = originalRequest.newBuilder()
                    .addHeader("Authorization", "Bearer $authToken")
                    .addHeader("Content-Type", "application/json")
                    .addHeader("Accept", "application/json")
                    .build()
                return chain.proceed(authenticatedRequest)
            }

            return chain.proceed(originalRequest)
        }
    }

    // --- Data Classes & Enums ---

    enum class HttpMethod {
        GET, POST, PUT, PATCH, DELETE
    }

    data class ApiResponse(
        val statusCode: Int,
        val body: String?,
        val headers: Map<String, String>,
        val isSuccessful: Boolean,
        val url: String
    ) {
        fun bodyAsJson(): JSONObject? {
            return try {
                body?.let { JSONObject(it) }
            } catch (e: Exception) {
                null
            }
        }
    }

    data class ApiError(
        val message: String,
        val statusCode: Int? = null,
        val responseBody: String? = null,
        val exception: Exception? = null,
        val url: String? = null
    )

    data class DeviceInfo(
        val ip: String,
        val port: Int,
        val responseData: String,
        val statusCode: Int
    )

    // --- Callbacks ---

    interface ApiCallback {
        fun onSuccess(response: ApiResponse)
