// --- Example Activity demonstrating usage ---

class MainActivity : AppCompatActivity() {

    private val iotClient = IoTHttpClient.getInstance()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Set auth token for cloud API
        iotClient.setAuthToken("your-jwt-token-here")

        // Example: Get data from cloud API
        fetchCloudDevices()

        // Example: Control a local IoT device
        controlLocalDevice()

        // Example: Discover devices on local network
        discoverLocalDevices()

        // Example: Generic request
        genericRequestExample()
    }

    private fun fetchCloudDevices() {
        iotClient.cloudGet(
            endpoint = "devices",
            queryParams = mapOf("status" to "online"),
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Cloud devices: ${response.body}")
                    val json = response.bodyAsJson()
                    // Process device list
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Cloud error: ${error.message}")
                }
            }
        )
    }

    private fun controlLocalDevice() {
        // Turn on a smart light via local HTTP
        val command = JSONObject().apply {
            put("action", "turn_on")
            put("brightness", 80)
            put("color", "#FFFFFF")
        }

        iotClient.devicePost(
            deviceIp = "192.168.1.100",
            port = 80,
            path = "/api/light/control",
            body = command,
            useHttps = false,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Device response: ${response.body}")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Device error: ${error.message}")
                }
            }
        )

        // Get device status
        iotClient.deviceGet(
            deviceIp = "192.168.1.100",
            port = 80,
            path = "/api/status",
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Device status: ${response.body}")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Status error: ${error.message}")
                }
            }
        )
    }

    private fun discoverLocalDevices() {
        iotClient.discoverDevices(
            subnet = "192.168.1",
            port = 80,
            path = "/info",
            callback = object : IoTHttpClient.DeviceDiscoveryCallback {
                override fun onDeviceFound(device: IoTHttpClient.DeviceInfo) {
                    Log.d("MainActivity", "Found device at ${device.ip}:${device.port}")
                }

                override fun onDiscoveryComplete(devices: List<IoTHttpClient.DeviceInfo>) {
                    Log.d("MainActivity", "Discovery complete. Found ${devices.size} devices.")
                    devices.forEach { device ->
                        Log.d("MainActivity", "  - ${device.ip}: ${device.responseData}")
                    }
                }
            }
        )
    }

    private fun genericRequestExample() {
        // Post sensor data to cloud
        val sensorData = JSONObject().apply {
            put("device_id", "sensor_001")
            put("temperature", 23.5)
            put("humidity", 45.2)
            put("timestamp", System.currentTimeMillis())
        }

        iotClient.request(
            url = "https://api.example.com/telemetry",
            method = IoTHttpClient.HttpMethod.POST,
            headers = mapOf("X-Device-ID" to "sensor_001"),
            body = sensorData,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Telemetry sent: ${response.statusCode}")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Telemetry error: ${error.message}")
                }
            }
        )

        // Access a local device with HTTPS (self-signed cert)
        iotClient.request(
            url = "https://192.168.1.50:8443/api/config",
            method = IoTHttpClient.HttpMethod.GET,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    Log.d("MainActivity", "Config: ${response.body}")
                }

                override fun onError(error: IoTHttpClient.ApiError) {
                    Log.e("MainActivity", "Config error: ${error.message}")
                }
            }
        )
    }

    override fun onDestroy() {
        super.onDestroy()
        iotClient.shutdown()
    }
